<?php
namespace Tests\Unit\Domain\Combat;use App\Domain\Combat\CombatActionResolver;use App\Domain\Combat\CombatResultStatus;use App\Domain\Combat\CombatSide;use App\Domain\Combat\CombatSimulator;use App\Domain\Combat\CombatTurnOrder;use App\Domain\Combat\Data\CombatantStats;use App\Domain\Random\RandomNumberGenerator;use PHPUnit\Framework\TestCase;class SequenceRandom implements RandomNumberGenerator{public $v;public $calls=0;public function __construct($v){$this->v=$v;}public function randomInt(int $a,int $b):int{$this->calls++;return array_shift($this->v);}}class CombatSimulatorTest extends TestCase{private function c($id,$hp=20,$attack=10,$speed=1){return new CombatantStats($id,$id,$hp,$hp,$attack,0,100,0,0,1.5,$speed,0);}private function sim($rng){$order=new CombatTurnOrder();return new CombatSimulator(new CombatActionResolver($rng,$order),$order);}public function test_historical_adapter_and_one_vs_many(){$r=$this->sim(new SequenceRandom([1,10000]))->simulate($this->c('p',20,50),$this->c('e',5,1));$this->assertSame(CombatResultStatus::CHARACTER_VICTORY,$r->status());$this->assertSame('p',$r->winnerIdentifier());$enc=$this->sim(new SequenceRandom([1,10000,1,10000,1,10000]))->simulateEncounter($this->c('p',20,50),[$this->c('e1',5,1),$this->c('e2',5,1)]);$this->assertSame(CombatSide::PLAYERS,$enc->winnerSideIdentifier());$this->assertCount(3,$enc->participants());}public function test_draw_has_no_extra_rng(){$rng=new SequenceRandom(array_fill(0,200,10000));$r=$this->sim($rng)->simulate($this->c('p',1000,0),$this->c('e',1000,0));$this->assertSame(100,$r->roundsCount());$this->assertSame(200,$rng->calls);}}
